import JSZip from 'jszip';
import { PDFDocument, rgb, StandardFonts, degrees } from 'pdf-lib';
import * as XLSX from 'xlsx';
import { getFileFromIndexedDB } from './indexedDBHelper';

export const addWatermarkToPDF = async (pdfBytes, watermarkText) => {
  try {
    const pdfDoc = await PDFDocument.load(pdfBytes);
    const pages = pdfDoc.getPages();
    if (pages.length === 0) return pdfBytes;

    const page = pages[0];
    const { width, height } = page.getSize();
    const rotation = page.getRotation().angle % 360;

    const font = await pdfDoc.embedFont(StandardFonts.HelveticaBold);
    const fontSize = 20;
    const margin = 30;
    const textWidth = font.widthOfTextAtSize(watermarkText, fontSize);
    const textHeight = fontSize; 

    let x, y;

    switch (rotation) {
      case 90:
        x = margin + textHeight; 
        y = height - margin - textWidth;
        break;
      case 180:
        x = margin + textWidth;
        y = margin;
        break;
      case 270:
        x = width - margin - textHeight;
        y = margin + textWidth;
        break;
      case 0:
      default:
        x = width - textWidth - margin;
        y = height - margin - textHeight;
        break;
    }

    page.drawText(watermarkText, {
      x,
      y,
      size: fontSize,
      font,
      color: rgb(1, 0, 0),
      rotate: degrees(rotation), 
    });

    return await pdfDoc.save();
  } catch (error) {
    console.error('Watermark error:', error);
    return pdfBytes;
  }
};

// Helper: get the folder ID regardless of whether file is a direct upload or AI-classified
const getFolderId = (result) => {
  return result.suggestedFolder?.id ?? result.folderId;
};

export const downloadZipClientSide = async (finalResults, folders) => {
  const zip = new JSZip();
  
  const folderPaths = {};
  for (const folder of folders) {
    const parts = [];
    const ids = folder.id.split('.');
    for (let i = 0; i < ids.length; i++) {
      const fid = ids.slice(0, i + 1).join('.');
      const f = folders.find(x => x.id === fid);
      if (f) parts.push(f.name);
    }
    const path = parts.join('/');
    folderPaths[folder.id] = path;
    zip.folder(path);
  }
  
  for (const result of finalResults) {
    const file = await getFileFromIndexedDB(result.fileName);
    if (!file) continue;
    
    let fileBytes = await file.arrayBuffer();
    
    if (file.name.toLowerCase().endsWith('.pdf')) {
      fileBytes = await addWatermarkToPDF(fileBytes, result.docCode);
    }
    
    const base = file.name.substring(0, file.name.lastIndexOf('.'));
    const ext = file.name.substring(file.name.lastIndexOf('.'));
    const newName = `${String(result.fileNumber).padStart(3, '0')}_${base}${ext}`;

    const folderId = getFolderId(result);
    const folderPath = folderPaths[folderId];
    if (!folderPath) {
      console.warn(`No folder path found for folderId "${folderId}" on file "${result.fileName}" — skipping.`);
      continue;
    }
    const path = `${folderPath}/${newName}`;
    
    zip.file(path, fileBytes);
  }
  
  const blob = await zip.generateAsync({ type: 'blob' });
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'DZO_Dokumenti.zip';
  document.body.appendChild(a);
  a.click();
  window.URL.revokeObjectURL(url);
  document.body.removeChild(a);
};

export const downloadExcelClientSide = async (finalResults, folders) => {
  // Build the full folder path array for a given folderId
  const buildFolderPath = (folderId) => {
    const parts = [];
    const ids = folderId.split('.');
    for (let i = 0; i < ids.length; i++) {
      const pid = ids.slice(0, i + 1).join('.');
      const f = folders.find(x => x.id === pid);
      if (f) parts.push(f.name);
    }
    return parts;
  };

  // Sort files by their full folder ID, segment by segment numerically
  // so "1.2.1" < "1.2.2" and "1.10" > "1.9" correctly
  const sorted = [...finalResults].sort((a, b) => {
    const idA = getFolderId(a);
    const idB = getFolderId(b);
    const partsA = idA.split('.').map(Number);
    const partsB = idB.split('.').map(Number);
    for (let i = 0; i < Math.max(partsA.length, partsB.length); i++) {
      const diff = (partsA[i] ?? -1) - (partsB[i] ?? -1);
      if (diff !== 0) return diff;
    }
    return 0;
  });

  // Group by FULL folder path (not just top level) to preserve hierarchy
  // e.g. "IV Inštalacije > 01 Strojne" is a separate group from "IV Inštalacije > 02 Elektro"
  const groups = []; // ordered array of { key, pathArr, items }

  sorted.forEach(res => {
    const folderId = getFolderId(res);
    const pathArr = buildFolderPath(folderId);
    const groupKey = pathArr.join(' > ') || 'Neznano';

    const existing = groups.find(g => g.key === groupKey);
    if (existing) {
      existing.items.push(res);
    } else {
      groups.push({ key: groupKey, pathArr, items: [res] });
    }
  });

  const data = [];
  const styleMap = [];
  let rowIndex = 0;

  groups.forEach(({ pathArr, items }) => {
    // One header row per depth level, indented visually
    // e.g.:
    //   IV Inštalacije          ← depth 0, bold large
    //     01 Strojne            ← depth 1, bold smaller
    pathArr.forEach((segment, depth) => {
      const indent = '  '.repeat(depth);
      data.push([`${indent}${segment}`, '', '', '', '', '']);
      styleMap.push({ row: rowIndex, type: depth === 0 ? 'section' : 'subsection', depth });
      rowIndex++;
    });

    // Table column headers
    data.push([
      'zap. št.',
      'ime dokazila oz. na kaj se dokazilo nanaša',
      'Originalna datoteka',
      'Izdajatelj',
      'št. dokazila',
      'datum'
    ]);
    styleMap.push({ row: rowIndex, type: 'header' });
    rowIndex++;

    // File rows
    let itemNumber = 1;
    items.forEach(res => {
      data.push([
        itemNumber++,
        res.documentTitle || '',
        res.originalFileName || res.fileName || '',
        res.issuer || '',
        res.documentNumber || '',
        res.date || ''
      ]);
      rowIndex++;
    });

    // Empty separator
    data.push(['', '', '', '', '', '']);
    rowIndex++;
  });

  const ws = XLSX.utils.aoa_to_sheet(data);

  // ===== STYLING =====
  styleMap.forEach(info => {
    const cellAddress = XLSX.utils.encode_cell({ r: info.row, c: 0 });

    if (info.type === 'section') {
      ws[cellAddress].s = {
        font: { bold: true, sz: 12 },
        alignment: { horizontal: 'left', vertical: 'center' }
      };
    }

    if (info.type === 'subsection') {
      ws[cellAddress].s = {
        font: { bold: true, sz: 10, color: { rgb: '444444' } },
        alignment: { horizontal: 'left', vertical: 'center' }
      };
    }

    if (info.type === 'header') {
      for (let col = 0; col < 6; col++) {
        const headerCell = XLSX.utils.encode_cell({ r: info.row, c: col });
        if (ws[headerCell]) {
          ws[headerCell].s = {
            font: { bold: true, sz: 10 },
            alignment: { horizontal: 'center', vertical: 'center' },
            border: {
              top: { style: 'thin', color: { rgb: '000000' } },
              bottom: { style: 'thin', color: { rgb: '000000' } }
            }
          };
        }
      }
    }
  });

  // Dotted borders on data rows
  data.forEach((row, rowIdx) => {
    if (styleMap.some(s => s.row === rowIdx)) return;
    for (let col = 0; col < 6; col++) {
      const cellAddr = XLSX.utils.encode_cell({ r: rowIdx, c: col });
      if (ws[cellAddr]) {
        ws[cellAddr].s = {
          border: {
            left: { style: 'dotted', color: { rgb: 'CCCCCC' } },
            right: { style: 'dotted', color: { rgb: 'CCCCCC' } },
            bottom: { style: 'dotted', color: { rgb: 'CCCCCC' } }
          }
        };
      }
    }
  });

  ws['!cols'] = [
    { wch: 8 },
    { wch: 45 },
    { wch: 35 },
    { wch: 30 },
    { wch: 20 },
    { wch: 12 },
    { wch: 5 }
  ];

  // Merge section/subsection header cells across all 6 columns
  if (!ws['!merges']) ws['!merges'] = [];
  styleMap.forEach(info => {
    if (info.type === 'section' || info.type === 'subsection') {
      ws['!merges'].push({
        s: { r: info.row, c: 0 },
        e: { r: info.row, c: 5 }
      });
    }
  });

  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, 'Seznam Dokumentov');
  XLSX.writeFile(wb, 'DZO_Dokumenti_Seznam.xlsx');
};